from typing import Dict, List

class InventorySystem:
    def __init__(self):
        self.items = {}
        self.players = {}

    async def handle_item_transfer(self, player_id: int, item_id: int, target_player_id: int):
        # Validate input
        if player_id not in self.players or target_player_id not in self.players:
            return False

        # Get the items from the players' inventories
        source_items = self.players[player_id].get("inventory", {})
        target_items = self.players[target_player_id].get("inventory", {})

        # Check if the item exists in the source player's inventory
        if item_id not in source_items:
            return False

        # Update the item ownership
        source_items[item_id]["owner"] = target_player_id
        target_items[item_id] = {"owner": player_id}

        # Update the players' inventories
        self.players[player_id]["inventory"] = source_items
        self.players[target_player_id]["inventory"] = target_items

        return True

    async def handle_item_request(self, player_id: int, item_id: int):
        # Validate input
        if player_id not in self.players or item_id not in self.items:
            return False

        # Get the item from the player's inventory
        source_items = self.players[player_id].get("inventory", {})
        target_item = source_items.get(item_id, None)

        if not target_item:
            return False

        # Update the item ownership
        target_item["owner"] = player_id

        # Update the player's inventory
        self.players[player_id]["inventory"] = source_items

        return True